 24→    /// throughout all the configurations, it uses that value, otherwise it defaults to the target's default.
 25→    public var productNameWithExtension: String {
 26→        var settingsProductNames: Set<String> = Set()
 27→
 28→        if let value = settings?.base["PRODUCT_NAME"], case let SettingValue.string(baseProductName) = value {
 29→            settingsProductNames.insert(baseProductName)
 30→        }
 31→        settings?.configurations.values.forEach { configuration in
 32→            if let value = configuration?.settings["PRODUCT_NAME"],
 33→               case let SettingValue.string(configurationProductName) = value
 34→            {
 35→                settingsProductNames.insert(configurationProductName)
 36→            }
 37→        }
 38→
 39→        let productName: String
 40→
 41→        if settingsProductNames.count == 1, !settingsProductNames.first!.contains("$") {
 42→            productName = settingsProductNames.first!
 43→        } else {
 44→            productName = self.productName
 45→        }
 46→
 47→        switch product {
 48→        case .staticLibrary, .dynamicLibrary:
 49→            return "lib\(productName).\(product.xcodeValue.fileExtension!)"
 50→        case .commandLineTool:
 51→            return productName
 52→        case _:
 53→            if let fileExtension = product.xcodeValue.fileExtension {
 54→                return "\(productName).\(fileExtension)"
 55→            } else {
 56→                return productName
 57→            }
 58→        }
 59→    }
 60→
 61→    /// Returns true if the file at the given path is a resource.
 62→    /// - Parameter path: Path to the file to be checked.
 63→    public static func isResource(path: AbsolutePath) -> Bool {
 64→        if path.isPackage {
 65→            return true
 66→        } else if !FileHandler.shared.isFolder(path) {
 67→            return true
 68→            // We filter out folders that are not Xcode supported bundles such as .app or .framework.
 69→        } else if let `extension` = path.extension, Target.validFolderExtensions.contains(`extension`) {
 70→            return true
 71→        } else {
 72→            return false
 73→        }
 74→    }
 75→
 76→    /// This method unfolds the source file globs subtracting the paths that are excluded and ignoring
 77→    /// the files that don't have a supported source extension.
 78→    /// - Parameter sources: List of source file glob to be unfolded.
 79→    public static func sources(
 80→        targetName: String,
 81→        sources: [SourceFileGlob],
 82→        fileSystem: FileSysteming
 83→    ) async throws -> [XcodeGraph.SourceFile] {
 84→        var sourceFiles: [AbsolutePath: XcodeGraph.SourceFile] = [:]
 85→        var invalidGlobs: [InvalidGlob] = []
 86→
 87→        for source in sources {
 88→            let sourcePath = try AbsolutePath(validating: source.glob)
 89→
 90→            // Paths that should be excluded from sources
 91→            var excluded: [AbsolutePath] = []
 92→            for path in source.excluding {
 93→                let path = try AbsolutePath(validating: path)
 94→                let globs = try await fileSystem.glob(
 95→                    directory: .root,
 96→                    include: [String(path.pathString.dropFirst())]
 97→                )
 98→                .collect()
 99→                excluded.append(contentsOf: globs)
100→            }
101→
102→            let paths: [AbsolutePath]
103→
104→            do {
105→                paths = try await fileSystem
106→                    .throwingGlob(directory: .root, include: [String(sourcePath.pathString.dropFirst())])
107→                    .collect()
108→                    .filter { !$0.isInOpaqueDirectory }
109→            } catch let GlobError.nonExistentDirectory(invalidGlob) {
110→                paths = []
111→                invalidGlobs.append(invalidGlob)
112→            }
113→
114→            Set(paths)
115→                .subtracting(excluded)
116→                .filter { path in
117→                    guard let `extension` = path.extension else { return false }
118→
119→                    let hasValidSourceExtensions = Target.validSourceExtensions
120→                        .contains(where: { $0.caseInsensitiveCompare(`extension`) == .orderedSame })
121→
122→                    if hasValidSourceExtensions {
123→                        // Addition check to prevent folders with name like `Foo.Swift` to be considered as source files.
124→                        return !FileHandler.shared.isFolder(path)
125→                    } else {
126→                        // There are extensions should be considered as source files even if they are folders.
127→                        return Target.validSourceCompatibleFolderExtensions
128→                            .contains(where: { $0.caseInsensitiveCompare(`extension`) == .orderedSame })
129→                    }
130→                }
131→                .forEach { sourceFiles[$0] = SourceFile(
132→                    path: $0,
133→                    compilerFlags: source.compilerFlags,
134→                    codeGen: source.codeGen,
135→                    compilationCondition: source.compilationCondition
136→                ) }
137→        }
138→
139→        if !invalidGlobs.isEmpty {
140→            throw TargetError.invalidSourcesGlob(targetName: targetName, invalidGlobs: invalidGlobs)
141→        }
142→
143→        return Array(sourceFiles.values)
144→    }
145→
146→    public var containsResources: Bool {
147→        if !resources.resources.isEmpty || !coreDataModels.isEmpty { return true }
148→        let resourceExtensions = Self.validResourceExtensions + Self.validResourceCompatibleFolderExtensions
149→        return buildableFolders.contains { folder in
150→            folder.resolvedFiles.contains { resourceExtensions.contains($0.path.extension ?? "") }
151→        }
152→    }
153→
154→    /// Returns if target is a generated resources bundle.
155→    public var isGeneratedResourcesBundle: Bool {
156→        guard product == .bundle else { return false }
157→        return bundleId.hasSuffix(".generated.resources")
158→    }
159→}
